definition.script:
pipeline {
    agent any
    options {
        timestamps()
        buildDiscarder(logRotator(numToKeepStr: '20'))
        timeout(time: 5, unit: 'MINUTES')
    }

    stages {
        stage('Spin up services') {
            steps {
                sh '''
                    echo "[integration-tests] starting fake postgres + redis..."
                    sleep 1
                    echo "services up"
                '''
            }
        }
        stage('Run integration suite') {
            steps {
                sh '''
                    set +e
                    echo "[integration-tests] pytest tests/integration/"
                    PICK=$((RANDOM % 3))
                    if [ "$PICK" -ne 2 ]; then
                        echo "TimeoutError: request to http://db:5432 timed out after 30000ms"
                        echo "FATAL: Cannot connect to DB"
                        echo "CRITICAL: integration suite aborted"
                        echo "Build FAILED"
                        sleep 1
                        exit 1
                    fi
                    sleep 1
                    echo "Integration suite passed (38/38)"
                    echo "BUILD SUCCESS"
                '''
            }
        }
    }

    post {
        always {
            script {
                def result    = currentBuild.currentResult ?: 'UNKNOWN'
                def duration  = currentBuild.duration ?: 0
                def payload   = "{\"job_name\":\"${env.JOB_NAME}\",\"build_number\":${env.BUILD_NUMBER},\"status\":\"${result}\",\"duration_ms\":${duration},\"url\":\"${env.BUILD_URL}\"}"
                sh """
                    curl -fsS -X POST \\
                         -H 'Content-Type: application/json' \\
                         -d '${payload}' \\
                         http://backend:8000/api/jenkins/webhook \\
                      || echo 'webhook unreachable'
                """
            }
        }
    }
}
